    todo_batch_id: String(input.todo_batch_id || input.todoBatchId || input.batch_id || input.batchId || "").trim(),
    todo_lines: String(input.todo_lines || input.todoLines || input.todos || input.items || input.prompt || input.text || "").trim(),
