          elapsedMs: job?.startedAtMs
            ? Math.max(0, getWorkspaceActivationDiagnosticNowMs() - job.startedAtMs)
            : 0,
          message: error || "Unable to activate shared MCP daemon.",
          mode: "background",
          repoPath,
          runtimeKey,
          workspaceName,
